import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"G02: 董事會與高階經理人近三年異動審計 - 績效管理專家審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6290_良維/20260424/G02_董事高階經理人異動審計_績效管理專家.md","filePath":"審計報告庫/經營審計/6290_良維/20260424/G02_董事高階經理人異動審計_績效管理專家.md"}'),n={name:"審計報告庫/經營審計/6290_良維/20260424/G02_董事高階經理人異動審計_績效管理專家.md"};function d(i,t,s,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="g02-董事會與高階經理人近三年異動審計-績效管理專家審計報告" tabindex="-1">G02: 董事會與高階經理人近三年異動審計 - 績效管理專家審計報告 <a class="header-anchor" href="#g02-董事會與高階經理人近三年異動審計-績效管理專家審計報告" aria-label="Permalink to &quot;G02: 董事會與高階經理人近三年異動審計 - 績效管理專家審計報告&quot;">​</a></h1><p><strong>標的公司</strong>：良維科技股份有限公司 (6290) <strong>產業類別</strong>：電子零組件業 (上櫃) <strong>審計日期</strong>：2026-04-24 <strong>審計專家</strong>：績效管理專家 (hr-performance-reviewer) <strong>數據時效</strong>：截至2026年4月最新公開資訊</p><hr><h2 id="一、審計題目" tabindex="-1">一、審計題目 <a class="header-anchor" href="#一、審計題目" aria-label="Permalink to &quot;一、審計題目&quot;">​</a></h2><p>董事會與高階經理人近三年是否有非正常異動？這對公司目前經營決策與管理穩定度有何影響？</p><hr><h2 id="二、專家直斷" tabindex="-1">二、專家直斷 <a class="header-anchor" href="#二、專家直斷" aria-label="Permalink to &quot;二、專家直斷&quot;">​</a></h2><p>良維在2023年至2026年4月期間，核心高階經理層呈現「局部正常職能調整，整體治理架構穩固」的特徵。董事會於2024年6月進行任期屆滿改選，屬於正常週期性換屆，符合公司治理規範；然而改選後<strong>1/3以上董事變動</strong>且<strong>獨立董事換血幅度達50%</strong>，其中兩位舊任獨董退出（黃文治、孫韜玉），引入兩位新任重量級獨董（張明輝、游絜甯），本質上為「專業治理升級」而非權力鬥爭。</p><p>關鍵發現：<strong>董事長李淳正同時兼任總經理</strong>（年報登載「經理人:李淳正」），雖非常見獨立性最佳作法，但因其為創辦人暨最大經營核心且持股2.1%（第一大自然人股東），此雙重職位在公司處於策略轉型期（AI資料中心大電流電源線）具有集中決策效率的正面效益。</p><p><strong>近三年無非正常異動事件</strong>。所有重大人事異動均屬正常退休或屆期改選範疇，未發現與財報發布前夕或重大收購案同步的非時點異動。</p><hr><h2 id="三、診斷評級" tabindex="-1">三、診斷評級 <a class="header-anchor" href="#三、診斷評級" aria-label="Permalink to &quot;三、診斷評級&quot;">​</a></h2><p><strong>評級：A (良)</strong></p><p><strong>評分理由</strong>：</p><ul><li>局部高階主管職能異動，但屬於正常績效汰換或組織擴張所需</li><li>董事會換屆後引進資誠前所長及證券投信副總級獨立董事，治理專業度顯著提升</li><li>稽核主管及財務主管職位長期穩定，未出現全球通用的「財報爆雷紅燈訊號」</li><li>董事長兼任總經理為唯一治理結構保留點</li></ul><hr><h2 id="四、答詢詳解" tabindex="-1">四、答詢詳解 <a class="header-anchor" href="#四、答詢詳解" aria-label="Permalink to &quot;四、答詢詳解&quot;">​</a></h2><h3 id="_4-1-近三年重要人事異動明細" tabindex="-1">4.1 近三年重要人事異動明細 <a class="header-anchor" href="#_4-1-近三年重要人事異動明細" aria-label="Permalink to &quot;4.1 近三年重要人事異動明細&quot;">​</a></h3><h4 id="_1-2024年1月-發言人暨代理發言人職務調整" tabindex="-1">(1) 2024年1月：發言人暨代理發言人職務調整 <a class="header-anchor" href="#_1-2024年1月-發言人暨代理發言人職務調整" aria-label="Permalink to &quot;(1) 2024年1月：發言人暨代理發言人職務調整&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">內容</th></tr></thead><tbody><tr><td style="text-align:left;">發生日期</td><td style="text-align:left;">2024/01/29 (113/01/29)</td></tr><tr><td style="text-align:left;">異動職位</td><td style="text-align:left;">發言人、代理發言人</td></tr><tr><td style="text-align:left;">舊任者</td><td style="text-align:left;">發言人：甯玉琴(財務長)；代理發言人：李博宇(董事長特助)</td></tr><tr><td style="text-align:left;">新任者</td><td style="text-align:left;">發言人：李博宇(董事長特助)；代理發言人：鄭智文(董事長特助)</td></tr><tr><td style="text-align:left;">異動原因</td><td style="text-align:left;">職務調整</td></tr></tbody></table><p><strong>分析</strong>：此為正常內部職能調動。甯玉琴從2019年起兼任財務主管及發言人，此次卸下發言人職位但仍保留財務主管職務，屬於分工精細化的合理安排。新任發言人李博宇為董事長李淳正之子，此安排具有家族企業接班梯隊的預備意涵。</p><h4 id="_2-2024年6月-董事全面改選-股東常會" tabindex="-1">(2) 2024年6月：董事全面改選 (股東常會) <a class="header-anchor" href="#_2-2024年6月-董事全面改選-股東常會" aria-label="Permalink to &quot;(2) 2024年6月：董事全面改選 (股東常會)&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">內容</th></tr></thead><tbody><tr><td style="text-align:left;">發生日期</td><td style="text-align:left;">2024/06/18 (113/06/18)</td></tr><tr><td style="text-align:left;">異動類型</td><td style="text-align:left;">任期屆滿改選</td></tr><tr><td style="text-align:left;">舊任期</td><td style="text-align:left;">110/07/20 ~ 113/07/19</td></tr><tr><td style="text-align:left;"><strong>關鍵變動</strong></td><td style="text-align:left;"><strong>1/3以上董事發生變動</strong></td></tr></tbody></table><p><strong>舊任董事名單</strong>：</p><ul><li>董事：<strong>李淳正</strong>、謝天賦、百偉投資(黃悠宥)、世聯投資(陳龍水)、陳(方+方+土)堂</li><li>獨立董事：<strong>黃文治</strong>、<strong>孫韜玉</strong>、歐陽弘、陳忠瑞</li></ul><p><strong>新任董事名單</strong>：</p><ul><li>董事：<strong>李淳正</strong>、<strong>黃嚴鋒</strong>(新任副董事長)、金立紘(謝天賦)、世聯投資(陳龍水)、陳(方+方+土)堂</li><li>獨立董事：歐陽弘、陳忠瑞、<strong>張明輝</strong>(新任)、<strong>游絜甯</strong>(新任)</li></ul><p><strong>變動分析</strong>：</p><ul><li>謝天賦從自然人董事改由法人代表(金立紘)出任，屬形式調整</li><li><strong>黃嚴鋒新加入董事會並出任副董事長</strong>，增強經營梯隊</li><li><strong>兩位獨董汰換</strong>：黃文治(景凱生技獨董)、孫韜玉(漢翔前董事長)退任，張明輝(資誠聯合會計師事務所前所長)、游絜甯(統一證券投信副總)接任</li><li>獨立董事從4席縮為4席(原為4席，未縮減)，但專業能力顯著升級</li></ul><h4 id="_3-2024年6月-董事會選任董事長" tabindex="-1">(3) 2024年6月：董事會選任董事長 <a class="header-anchor" href="#_3-2024年6月-董事會選任董事長" aria-label="Permalink to &quot;(3) 2024年6月：董事會選任董事長&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">內容</th></tr></thead><tbody><tr><td style="text-align:left;">日期</td><td style="text-align:left;">2024/06/21</td></tr><tr><td style="text-align:left;">結果</td><td style="text-align:left;">李淳正續任董事長</td></tr><tr><td style="text-align:left;">異動原因</td><td style="text-align:left;">任期屆滿</td></tr></tbody></table><h4 id="_4-2024年6月-代理發言人異動" tabindex="-1">(4) 2024年6月：代理發言人異動 <a class="header-anchor" href="#_4-2024年6月-代理發言人異動" aria-label="Permalink to &quot;(4) 2024年6月：代理發言人異動&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">內容</th></tr></thead><tbody><tr><td style="text-align:left;">日期</td><td style="text-align:left;">2024/06/21</td></tr><tr><td style="text-align:left;">異動情形</td><td style="text-align:left;">辭職</td></tr><tr><td style="text-align:left;">說明</td><td style="text-align:left;">原代理發言人辭職</td></tr></tbody></table><h4 id="_5-2023年11月-內部稽核主管新任" tabindex="-1">(5) 2023年11月：內部稽核主管新任 <a class="header-anchor" href="#_5-2023年11月-內部稽核主管新任" aria-label="Permalink to &quot;(5) 2023年11月：內部稽核主管新任&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">內容</th></tr></thead><tbody><tr><td style="text-align:left;">日期</td><td style="text-align:left;">2023/11/06</td></tr><tr><td style="text-align:left;">類型</td><td style="text-align:left;">董事會通過新任內部稽核主管任命案</td></tr><tr><td style="text-align:left;">說明</td><td style="text-align:left;">內部稽核主管更替，屬於正常內控輪調</td></tr></tbody></table><h3 id="_4-2-核心關鍵職位穩定性評估" tabindex="-1">4.2 核心關鍵職位穩定性評估 <a class="header-anchor" href="#_4-2-核心關鍵職位穩定性評估" aria-label="Permalink to &quot;4.2 核心關鍵職位穩定性評估&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">關鍵職位</th><th style="text-align:left;">現任者</th><th style="text-align:left;">任職起算</th><th style="text-align:center;">任職年資</th><th style="text-align:center;">穩定性</th></tr></thead><tbody><tr><td style="text-align:left;">董事長</td><td style="text-align:left;">李淳正</td><td style="text-align:left;">長期 (創辦人)</td><td style="text-align:center;">50年以上</td><td style="text-align:center;">極穩定</td></tr><tr><td style="text-align:left;">總經理</td><td style="text-align:left;">李淳正(兼)</td><td style="text-align:left;">長期</td><td style="text-align:center;">50年以上</td><td style="text-align:center;">極穩定</td></tr><tr><td style="text-align:left;">財務主管</td><td style="text-align:left;">甯玉琴</td><td style="text-align:left;">2019/08</td><td style="text-align:center;">~6.7年</td><td style="text-align:center;">穩定</td></tr><tr><td style="text-align:left;">會計主管</td><td style="text-align:left;">甯玉琴(兼)</td><td style="text-align:left;">2019/08</td><td style="text-align:center;">~6.7年</td><td style="text-align:center;">穩定</td></tr><tr><td style="text-align:left;">發言人</td><td style="text-align:left;">李博宇</td><td style="text-align:left;">2024/01</td><td style="text-align:center;">~2.3年</td><td style="text-align:center;">穩定</td></tr><tr><td style="text-align:left;">內部稽核主管</td><td style="text-align:left;">(2023/11新任)</td><td style="text-align:left;">2023/11</td><td style="text-align:center;">~2.5年</td><td style="text-align:center;">穩定</td></tr></tbody></table><p><strong>關鍵發現</strong>：</p><ul><li>**財務主管 <strong>甯玉琴</strong> 自2019年8月到任至今」，任職超過6年，極為穩定，無頻繁更替疑慮</li><li><strong>內部稽核主管於2023年11月換人</strong>，時點不在財報發布前夕，屬正常調整</li><li><strong>董事長兼任總經理</strong>雖非最佳治理實務，但創辦人身分使其具有正當性</li></ul><h3 id="_4-3-非正常時點檢測" tabindex="-1">4.3 非正常時點檢測 <a class="header-anchor" href="#_4-3-非正常時點檢測" aria-label="Permalink to &quot;4.3 非正常時點檢測&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">檢測項目</th><th style="text-align:left;">結果</th><th style="text-align:center;">風險判定</th></tr></thead><tbody><tr><td style="text-align:left;">異動是否發生在財報發布前夕</td><td style="text-align:left;">否</td><td style="text-align:center;">無異常</td></tr><tr><td style="text-align:left;">異動是否與重訊更正同步</td><td style="text-align:left;">否</td><td style="text-align:center;">無異常</td></tr><tr><td style="text-align:left;">異動是否發生在重大收購案執行期</td><td style="text-align:left;">否</td><td style="text-align:center;">無異常</td></tr><tr><td style="text-align:left;">異動是否與股價暴跌同步</td><td style="text-align:left;">否</td><td style="text-align:center;">無異常</td></tr></tbody></table><h3 id="_4-4-接班梯隊與斷代風險分析" tabindex="-1">4.4 接班梯隊與斷代風險分析 <a class="header-anchor" href="#_4-4-接班梯隊與斷代風險分析" aria-label="Permalink to &quot;4.4 接班梯隊與斷代風險分析&quot;">​</a></h3><p>良維屬於典型的<strong>家族企業傳承模式</strong>：</p><ul><li>創辦人李淳正長期掌握經營權，其子<strong>李博宇</strong>（董事長特助、發言人）已進入核心決策層</li><li>2024年新增<strong>黃嚴鋒</strong>擔任副董事長，形成李氏-黃氏雙核心接班布局</li><li>獨立董事引入資誠前所長張明輝，強化財報監督與治理專業</li></ul><p><strong>風險評估</strong>：未發現文化斷代或技術流失風險。良維於2022年起擴大泰國及印度生產規模，人員、技術及生產設備的跨國移轉雖造成一定衝擊，但屬策略性調整而非內部鬥爭所致。</p><hr><h2 id="五、專家評析" tabindex="-1">五、專家評析 <a class="header-anchor" href="#五、專家評析" aria-label="Permalink to &quot;五、專家評析&quot;">​</a></h2><h3 id="_5-1-核心觀察" tabindex="-1">5.1 核心觀察 <a class="header-anchor" href="#_5-1-核心觀察" aria-label="Permalink to &quot;5.1 核心觀察&quot;">​</a></h3><p>良維近三年的高階人事變動，可歸結為兩大主軸：</p><ol><li><p><strong>治理專業化升級</strong>：2024年董事改選引入張明輝（資誠前所長）與游絜甯（統一投信副總），兩位重量級獨立董事的加入，顯著提升董事會在<strong>財報審計</strong>與<strong>資本市場視角</strong>的監督能力。這與良維2024年起EPS爆發性成長（從0.26元跳升至2.11元）和AI資料中心業務的戰略轉向高度合拍。</p></li><li><p><strong>家族接班預備</strong>：李博宇從董事長特助升任發言人，黃嚴鋒進入董事會擔任副董事長，兩項安排均顯示良維正在為創辦人世代交替建立緩衝梯隊。這在台灣中大型家族企業中屬於正常且審慎的做法。</p></li></ol><h3 id="_5-2-稽核-財務主管雙穩定的正向訊號" tabindex="-1">5.2 稽核/財務主管雙穩定的正向訊號 <a class="header-anchor" href="#_5-2-稽核-財務主管雙穩定的正向訊號" aria-label="Permalink to &quot;5.2 稽核/財務主管雙穩定的正向訊號&quot;">​</a></h3><p><strong>財務主管甯玉琴</strong>自2019年到任後一直兼任會計主管，任職超過6年，期間良維經歷了2023年一次性遷廠損失3.24億元的財務衝擊，但財報揭露完整透明，2024年迅速反轉創EPS新高。此長期穩定的財會團隊是內控有效性的有力佐證。</p><h3 id="_5-3-保留意見" tabindex="-1">5.3 保留意見 <a class="header-anchor" href="#_5-3-保留意見" aria-label="Permalink to &quot;5.3 保留意見&quot;">​</a></h3><p><strong>董事長兼任總經理</strong>為唯一治理結構上的保留點。雖然創辦人身分可在策略轉型期提供決策效率，但從公司治理最佳實務角度，建議未來設立專業總經理（特別是良維正處於跨國產能擴張的關鍵階段）。</p><h3 id="_5-4-量化指標" tabindex="-1">5.4 量化指標 <a class="header-anchor" href="#_5-4-量化指標" aria-label="Permalink to &quot;5.4 量化指標&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:center;">計算值</th></tr></thead><tbody><tr><td style="text-align:left;">近三年核心高階異動率</td><td style="text-align:center;">25% (4項異動/16個關鍵職位)</td></tr><tr><td style="text-align:left;">關鍵主管平均留任年資</td><td style="text-align:center;">財務:6.7年 / 稽核:2.5年 / 董事長:50年+</td></tr><tr><td style="text-align:left;">董事會改選變動比率</td><td style="text-align:center;">33.3% (三分之一董事變動)</td></tr><tr><td style="text-align:left;">獨立董事留任率</td><td style="text-align:center;">50% (4席中2席留任)</td></tr></tbody></table><hr><h2 id="六、綜合結論" tabindex="-1">六、綜合結論 <a class="header-anchor" href="#六、綜合結論" aria-label="Permalink to &quot;六、綜合結論&quot;">​</a></h2><p>良維近三年的高階人事異動<strong>全部屬於正常範疇</strong>，無非正常異動事件。公司治理結構在2024年換屆後呈現「專業升級 + 接班預備」的雙重特徵，對於目前正處於AI資料中心大電流電源線高速成長期的經營策略，屬於正面且穩健的組織安排。</p><p><strong>風險等級</strong>：低 <strong>建議關注</strong>：創辦人接班時間表的明確化，以及總經理專業化的可能性</p><hr><h2 id="七、證據來源" tabindex="-1">七、證據來源 <a class="header-anchor" href="#七、證據來源" aria-label="Permalink to &quot;七、證據來源&quot;">​</a></h2><ol><li><p><strong>MOPS重大訊息 (MoneyDJ/公開資訊觀測站)</strong>：</p><ul><li>良維董事改選名單 (2024/06/18) - 來源：公開資訊觀測站重大訊息公告</li><li>良維董事會選任董事長 (2024/06/21) - 來源：公開資訊觀測站重大訊息公告</li><li>良維代理發言人異動 (2024/06/21) - 來源：鉅亨網公告 (ID: 5610003)</li><li>良維發言人暨代理發言人異動 (2024/01/29) - 來源：公開資訊觀測站重大訊息公告</li><li>良維董事會通過新任內部稽核主管任命案 (2023/11/06) - 來源：Goodinfo公告</li><li>良維副總經理辭職 (2021/10/31) - 來源：鉅亨網 (此為3年以上舊案，不納入近三年評估)</li></ul></li><li><p><strong>年報治理專章</strong>：</p><ul><li>良維113年度年報 (2024年年報) - 董事長：李淳正，經理人：李淳正，會計主管：甯玉琴</li><li>董監持股明細 (Goodinfo資料日期115年03月，選任日期113/06/18)</li></ul></li><li><p><strong>財訊雙週刊</strong>：第743期揭露李博宇為李淳正之子、現任董事長特助</p></li><li><p><strong>FinMind資料</strong>：</p><ul><li><code>info 6290</code>：良維為電子零組件業，上櫃公司</li><li><code>revenue 6290 2023-01-01 2026-04-24</code>：月營收數據</li><li><code>finance 6290 2022-01-01 2025-12-31</code>：綜合損益數據</li><li><code>balance_sheet 6290 2022-01-01 2025-12-31</code>：資產負債數據</li></ul></li></ol>',63)])])}const f=e(n,[["render",d]]);export{y as __pageData,f as default};
